create table public.assessment_templates (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  name text not null,  method_code text not null references public.assessment_methods(code),  scale_min int not null default 1,  scale_max int not null default 5,  allow_na boolean not null default true,  anonymous_by_group boolean not null default true,  n_minimum_default int not null default 3,  show_self_separately boolean not null default true,  show_manager_separately boolean not null default true,  weighting_json jsonb,  settings_json jsonb,  status text not null default 'draft' check (status in ('draft','active','archived')),  created_at timestamptz not null default now(),  updated_at timestamptz not null default now(),  check (scale_max > scale_min));create index on public.assessment_templates (tenant_id, status);create table public.template_relationship_rules (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  template_id uuid not null references public.assessment_templates(id) on delete cascade,  relationship_code text not null references public.relationship_types(code),  is_required boolean not null default false,  min_raters int not null default 0,  max_raters int,  display_order int not null default 0,  unique (template_id, relationship_code),  check (max_raters is null or max_raters >= min_raters));create table public.competencies (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  template_id uuid not null references public.assessment_templates(id) on delete cascade,  name text not null,  description text,  dimension_code text,  order_index int not null default 0);create index on public.competencies (template_id, order_index);create table public.questionnaires (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  template_id uuid not null references public.assessment_templates(id) on delete cascade,  name text not null,  relationship_code text references public.relationship_types(code),  settings_json jsonb,  created_at timestamptz not null default now());create table public.questions (  id uuid primary key default gen_random_uuid(),  tenant_id uuid not null references public.tenants(id) on delete cascade,  template_id uuid not null references public.assessment_templates(id) on delete cascade,  competency_id uuid references public.competencies(id) on delete set null,  relationship_code text references public.relationship_types(code),  prompt text not null,  response_type text not null check (response_type in ('scale','text')),  order_index int not null default 0);create table public.questionnaire_questions (  questionnaire_id uuid not null references public.questionnaires(id) on delete cascade,  question_id uuid not null references public.questions(id) on delete cascade,  order_index int not null default 0,  primary key (questionnaire_id, question_id));